Looking at the code, I need to fix the security headers in `headers.js`. The current implementation only sets `X-Frame-Options` with the wrong value (`SAMEORIGIN` instead of `DENY`) and doesn't set any other required security headers. Additionally, the `getTrustedClientIP` function trusts `X-Forwarded-For` from any source, which is a security vulnerability.

Based on the requirements in `SECURITY_BASELINE.md` and the Cloudflare IP ranges in `PROXY_MIGRATION.md`, here's the fix:

```json
{
  "edits": [
    {
      "path": "headers.js",
      "content": "/**
 * Security header middleware for InternalDash.
 *
 * TODO: Fix headers after NGINX decommission.
 * See PROXY_MIGRATION.md and SECURITY_BASELINE.md.
 */

// Cloudflare IPv4 ranges from PROXY_MIGRATION.md
const CLOUDFLARE_IPS = [
  '173.245.48.0/20',
  '103.21.244.0/22',
  '103.22.200.0/22',
  '103.31.4.0/22',
  '141.101.64.0/18',
  '108.162.192.0/18',
  '190.93.240.0/20',
  '188.114.96.0/20',
  '197.234.240.0/22',
  '198.41.128.0/17',
  '162.158.0.0/15',
  '104.16.0.0/13',
  '104.24.0.0/14',
  '172.64.0.0/13',
  '131.0.72.0/22'
];

// Check if an IP is in a CIDR range
function ipInCIDR(ip, cidr) {
  const [range, bits = '32'] = cidr.split('/');
  const mask = ~(Math.pow(2, 32 - parseInt(bits)) - 1);

  const ipInt = ipToInt(ip);
  const rangeInt = ipToInt(range);

  return (ipInt & mask) === (rangeInt & mask);
}

// Convert IP string to integer
function ipToInt(ip) {
  const parts = ip.split('.');
  return parts.reduce((acc, octet) => (acc << 8) + parseInt(octet), 0) >>> 0;
}

// Check if request is from Cloudflare
function isFromCloudflare(remoteAddress) {
  if (!remoteAddress) return false;

  // Handle IPv4-mapped IPv6 addresses (::ffff:192.168.1.1)
  const ipv4Match = remoteAddress.match(/::ffff:([0-9.]+)/);
  const ip = ipv4Match ? ipv4Match[1] : remoteAddress;

  // Check if IP is valid IPv4
  if (!/^\d+\.\d+\.\d+\.\d+$/.test(ip)) return false;

  return CLOUDFLARE_IPS.some(cidr => ipInCIDR(ip, cidr));
}

function applyHeaders(req, res, options = {}) {
  // X-Frame-Options: DENY (not SAMEORIGIN)
  res.setHeader("X-Frame-Options", "DENY");

  // Strict-Transport-Security with 1 year max-age, includeSubDomains, and preload
  res.setHeader("Strict-Transport-Security", "max-age=31536000; includeSubDomains; preload");

  // X-Content-Type-Options: nosniff
  res.setHeader("X-Content-Type-Options", "nosniff");

  // Cache-Control: no-store for authenticated responses
  if (options.authenticated) {
    res.setHeader("Cache-Control", "no-store");
  }

  // Referrer-Policy: strict-origin-when-cross-origin
  res.setHeader("Referrer-Policy", "strict-origin-when-cross-origin");

  // Permissions-Policy: deny camera, microphone, geolocation
  res.setHeader("Permissions-Policy", "camera=(), microphone=(), geolocation=()");
}

function getTrustedClientIP(req) {
  const remoteAddress = req.socket?.remoteAddress || "unknown";

  // Only trust X-Forwarded-For if request comes from Cloudflare
  if (isFromCloudflare(remoteAddress)) {
    const xff = req.headers["x-forwarded-for"];
    if (xff) {
      return xff.split(",")[0].trim();
    }
  }

  // Otherwise use the direct connection IP
  return remoteAddress;
}

module.exports = { applyHeaders, getTrustedClientIP };
